1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	export function nextGeneration(liveCells: Cell[]): Cell[] {
12	  const liveKeys = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
13	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
14	
15	  for (const [x, y] of liveCells) {
16	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
17	      const nx = x + dx;
18	      const ny = y + dy;
19	      const k = cellKey(nx, ny);
20	      const entry = neighborCounts.get(k);
21	      if (entry) {
22	        entry.count += 1;
23	      } else {
24	        neighborCounts.set(k, { cell: [nx, ny], count: 1 });
25	      }
26	    }
27	  }
28	
29	  const survivors: Cell[] = [];
30	  for (const [k, { cell, count }] of neighborCounts) {
31	    const isAlive = liveKeys.has(k);
32	    if (count === 3 || (isAlive && count === 2)) {
33	      survivors.push(cell);
34	    }
35	  }
36	
37	  return survivors;
38	}
